import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { API_BASE_URL } from '../config';

const Home = () => {
    const [userInfo, setUserInfo] = useState(null);

    useEffect(() => {
        const fetchUserInfo = async () => {
            const accessToken = localStorage.getItem('accessToken');
            const response = await fetch(`${API_BASE_URL}/account/get_me`, {
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                },
            });
            if (!response.ok) {
                throw new Error('Failed to fetch user info');
            }
            const data = await response.json();
            setUserInfo(data);
        };

        fetchUserInfo();
    }, []);

    return (
        <div>
            <h1>Home</h1>
            {userInfo && (
                <div>
                    <p>Username: {userInfo.username}</p>
                    <p>Email: {userInfo.email}</p>
                    // 他のユーザ情報もここに表示
                </div>
            )}
            <Link to="/eventer/manage">Eventer Manage</Link>
            <br></br><br></br>
            <Link to="/vendor/manage">Vendor Manage</Link>
            <h1>Register</h1>
            <Link to="/eventer/register">Eventer Register</Link>
            <br></br><br></br>
            <Link to="/vendor/register">Vendor Register</Link>
        </div>
    );
};

export default Home;
